import pandas as pd

def check_start_stop(sequence):
    start_codon = sequence.startswith('ATG')
    stop_codons = sequence.endswith(('TAA', 'TAG', 'TGA'))
    return int(start_codon), int(stop_codons)

def check_motif(sequence):
    return int('AGAT' in sequence)

def check_consecutive_g(sequence):
    return int('GGG' in sequence)

def process_samples(samples):
    samples['has_start'] = samples['dna_sequence'].apply(lambda x: check_start_stop(x)[0])
    samples['has_stop'] = samples['dna_sequence'].apply(lambda x: check_start_stop(x)[1])
    samples['has_arat'] = samples['dna_sequence'].apply(check_motif)
    samples['has_ggg'] = samples['dna_sequence'].apply(check_consecutive_g)
    return samples.sort_values('sample_id').reset_index(drop=True)

samples = pd.DataFrame({
    'sample_id': [1, 2, 3, 4, 5, 6, 7],
    'dna_sequence': ['ATGC5AGCTAGCTA', 'GGGTDAATTC', 'ATAGCGTAGCTA', 'XTGGGGTCAAA', 'TsAGTfAG4CAG', 'ATATDGCGCyaG', 'SGTATGCGyCGT'],
    'species': ['Human', 'Human', 'Human', 'Mouse', 'Mouse', 'Zebrafish', 'Zebrafish']
})

result = process_samples(samples)
print(result)

