def validate_dna_sequence(sequence):
    start_codon = 'ATG'
    stop_codons = ['TAA', 'TAG', 'TGA']

    # Validate the start codon
    if not sequence.startswith(start_codon):
        return False

    # Validate the stop codons
    for i in range(0, len(sequence), 3):
        codon = sequence[i:i+3]
        if codon in stop_codons:
            return True

    return False

def read_genetic_code(file_name):
    genetic_code = {}

    with open(file_name, 'r') as file:
        lines = file.readlines()

        for line in lines[2:]:
            line = line.strip().split()
            amino_acid = line[0]
            codons = line[1:]
            genetic_code[amino_acid] = codons

    return genetic_code

def translate_dna_sequence(sequence, genetic_code):
    amino_acid_sequence = ''

    for i in range(0, len(sequence), 3):
        codon = sequence[i:i+3]

        for amino_acid, codons in genetic_code.items():
            if codon in codons:
                amino_acid_sequence += amino_acid

    return amino_acid_sequence

def main():
    dna_sequence = input('Enter the DNA sequence: ')
    file_name = input('Enter the genetic code file name: ')

    genetic_code = read_genetic_code(file_name)

    if validate_dna_sequence(dna_sequence):
        amino_acid_sequence = translate_dna_sequence(dna_sequence, genetic_code)
        print('The amino acid sequence is:', amino_acid_sequence)
    else:
        print('The DNA sequence is not valid.')

