class DNAAnalyzer:
    def __init__(self, dna_sequence):
        self.dna_sequence = dna_sequence

    def find_start_codon(self):
        start_codon = 'ATG'
        return self.dna_sequence.find(start_codon)

    def find_stop_codons(self):
        stop_codons = ['TAA', 'TAG', 'TGA']
        return [self.dna_sequence.find(stop_codon) for stop_codon in stop_codons]

    def find_g_quadruplex(self):
        g_quadruplex = 'G'
        ggg = 'GGG'
        return [i for i in range(len(self.dna_sequence)) if self.dna_sequence.startswith(g_quadruplex, i) and self.dna_sequence.startswith(ggg, i)]

def analyze_dna_sequences(dna_sequences):
    analysis_results = []
    for dna_sequence in dna_sequences:
        analyzer = DNAAnalyzer(dna_sequence)
        start_codon_index = analyzer.find_start_codon()
        stop_codon_indices = analyzer.find_stop_codons()
        g_quadruplex_indices = analyzer.find_g_quadruplex()
        analysis_results.append({
            'start_codon_index': start_codon_index,
            'stop_codon_indices': stop_codon_indices,
            'g_quadruplex_indices': g_quadruplex_indices
        })
    return analysis_results

